const d = $input.item.json.Felder || $input.item.json;
const systemPrompt = `Du bist der Social-Media-Texter der Physiotherapiepraxis Physio Fuchs.
Du schreibst Instagram-Captions auf Deutsch fuer eine moderne, empathische Physiotherapiepraxis.
TONALITAET:
- Warm, professionell, motivierend - nie arrogant oder klinisch
- Duzen der Community ist erwuenscht
- Emojis: maximal 3-5 pro Caption, nur unterstuetzend
- Keine Clickbait-Formulierungen
- Keine medizinischen Versprechen (kein 'heilt', 'kuriert')
- Erlaubt: 'kann helfen', 'unterstuetzt', 'lindert haeufig'
CAPTION-AUFBAU:
1. Hook (erste Zeile, max. 12 Woerter) - stopp-wuerdig, direkte Ansprache
2. Hauptinhalt (3-5 Saetze) - Mehrwert, Tipps oder konkreter Einblick
3. Handlungsaufruf (1 Satz) - Termin buchen, Kommentieren oder Beitrag speichern
WICHTIG: Keine Hashtags in der Caption selbst.
AUSGABE: Nur reines JSON ohne Markdown-Backticks oder erklaerenden Text davor/danach.
Exaktes Format:
{"variante_1":{"caption":"...","hook_preview":"...(erste 15 Zeichen)","ton":"informativ"},"variante_2":{"caption":"...","hook_preview":"...","ton":"persoenlich"},"variante_3":{"caption":"...","hook_preview":"...","ton":"motivierend"},"hashtag_set_1":["#tag1","#tag2"],"hashtag_set_2":["#tag1","#tag2"]}`;

const thema = d.Field_1 || 'Physiotherapie';
const postTyp = d.Field_2 || 'Tipp';
const brief = d.Field_3 || '';
const datum = d.Field_4 || '';
const hashtag = d.Field_7 || '';
const wochentag = new Date(datum).toLocaleDateString('de-DE', {weekday: 'long'}) || 'Montag';
const monat = new Date().getMonth();
const jahreszeit = monat <= 1 || monat === 11 ? 'Winter' : monat <= 4 ? 'Frühling' : monat <= 7 ? 'Sommer' : 'Herbst';

const userMessage = `BRIEF VON JUDITH:
Thema: ${thema}
Post-Typ: ${postTyp}
Anweisung: ${brief}
KONTEXT:
- Wochentag der Veroeffentlichung: ${wochentag}
- Jahreszeit: ${jahreszeit}
VERFUEGBARER HASHTAG-POOL (waehle die 25-30 passendsten aus):
Kern-Tags: #physiofuchs #physiotherapie #physio #gesundheit #wohlbefinden
Themen-Tags (${thema}): ${hashtag}
Reichweiten-Tags: #gesundheitstipp #fitnessmotivation #bewegung #schmerzfrei #physiotherapeut
Lokale Tags: #physiotherapieStadt #StadtGesundheit
Erstelle alle 3 Varianten im vorgegebenen JSON-Format. Nur reines JSON ausgeben, keine Erklaerungen.`;

return {
  json: {
    model: 'claude-sonnet-4-6',
    max_tokens: 2048,
    system: systemPrompt,
    messages: [{ role: 'user', content: userMessage }]
  }
};

const response = $input.item.json;

// Fehlercheck
if (!response.content || !response.content[0]) {
  throw new Error('Keine Antwort von Claude. Response: ' + JSON.stringify(response).substring(0, 300));
}

const rawText = response.content[0].text;

// JSON extrahieren (falls Claude Backticks mitliefert)
let parsed;
try {
  const cleaned = rawText
    .replace(/```json\n?/gi, '')
    .replace(/```\n?/g, '')
    .trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  // Fallback: JSON aus dem Text herausschneiden
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch(e2) {
      throw new Error('Claude-Output ist kein valides JSON:\n' + rawText.substring(0, 400));
    }
  } else {
    throw new Error('Kein JSON in Claude-Output gefunden:\n' + rawText.substring(0, 400));
  }
}

// Kosten berechnen (Claude Sonnet Preise Stand 2025)
const inputTokens = response.usage?.input_tokens || 0;
const outputTokens = response.usage?.output_tokens || 0;
const costEur = Math.round((inputTokens * 0.000003 + outputTokens * 0.000015) * 100) / 100;

return {
  json: {
    // Captions
    v1_caption: parsed.variante_1?.caption || '',
    v1_hook: parsed.variante_1?.hook_preview || '',
    v1_ton: parsed.variante_1?.ton || 'informativ',

    v2_caption: parsed.variante_2?.caption || '',
    v2_hook: parsed.variante_2?.hook_preview || '',
    v2_ton: parsed.variante_2?.ton || 'persoenlich',

    v3_caption: parsed.variante_3?.caption || '',
    v3_hook: parsed.variante_3?.hook_preview || '',
    v3_ton: parsed.variante_3?.ton || 'motivierend',

    // Hashtags als String (fertig fuer Instagram)
    hashtags_set_1: Array.isArray(parsed.hashtag_set_1) ? parsed.hashtag_set_1.join(' ') : '',
    hashtags_set_2: Array.isArray(parsed.hashtag_set_2) ? parsed.hashtag_set_2.join(' ') : '',

    // Hashtags als Array (fuer spaetere Verarbeitung)
    hashtags_array_1: parsed.hashtag_set_1 || [],
    hashtags_array_2: parsed.hashtag_set_2 || [],

    // Metadaten
    input_tokens: inputTokens,
    output_tokens: outputTokens,
    cost_eur: costEur,
    generated_at: new Date().toISOString(),
    model: 'claude-sonnet-4-20250514'
  }
};

